import React, { useState, useContext, useMemo, useEffect, useCallback } from "react";
import axios from "axios";
import GeneralContext from "./GeneralContext";
import VerticalGraph from "./VerticalGraph";
import "./BuyActionWindow.css";

const API_URL = process.env.REACT_APP_API_URL || "http://localhost:3002";

const BuyActionWindow = ({ uid, currentPrice = 0 }) => {
  const { closeBuyWindow, refreshDashboard } = useContext(GeneralContext);

  const [mode, setMode] = useState("BUY");
  const [stockQuantity, setStockQuantity] = useState(1);
  const [stockPrice, setStockPrice] = useState(currentPrice);
  const [holdings, setHoldings] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  // ================================
  // Sync price when stock changes
  // ================================
  useEffect(() => {
    setStockPrice(currentPrice || 0);
  }, [currentPrice]);

  // ================================
  // Fetch Holdings (for graph)
  // ================================
  const fetchHoldings = useCallback(async () => {
    try {
      const res = await axios.get(`${API_URL}/allHoldings`);
      setHoldings(Array.isArray(res.data) ? res.data : []);
    } catch (err) {
      console.error("Failed to fetch holdings:", err);
    }
  }, []);

  useEffect(() => {
    fetchHoldings();
  }, [fetchHoldings]);

  // ================================
  // Dynamic Total Calculation
  // ================================
  const totalAmount = useMemo(() => {
    return Number(stockQuantity) * Number(stockPrice);
  }, [stockQuantity, stockPrice]);

  // ================================
  // Graph Data
  // ================================
  const graphData = useMemo(() => {
    if (!holdings.length) return null;

    return {
      labels: holdings.map((stock) => stock.name),
      datasets: [
        {
          label: "Average Price",
          data: holdings.map((stock) => stock.avg),
          backgroundColor: "rgba(54, 162, 235, 0.7)",
          borderRadius: 6,
        },
        {
          label: "Current Price",
          data: holdings.map((stock) => stock.price),
          backgroundColor: holdings.map((stock) =>
            stock.price >= stock.avg
              ? "rgba(75, 192, 192, 0.7)"
              : "rgba(255, 99, 132, 0.7)"
          ),
          borderRadius: 6,
        },
      ],
    };
  }, [holdings]);

  // ================================
  // Submit Order
  // ================================
  const handleSubmit = async () => {
    setError("");

    if (!uid) {
      setError("No stock selected.");
      return;
    }

    if (stockQuantity <= 0 || stockPrice <= 0) {
      setError("Quantity and price must be greater than zero.");
      return;
    }

    try {
      setLoading(true);

      await axios.post(`${API_URL}/newOrder`, {
        name: uid,
        qty: Number(stockQuantity),
        price: Number(stockPrice),
        mode,
      });

      await fetchHoldings();        // Update graph instantly
      refreshDashboard?.();         // Update dashboard
      closeBuyWindow();             // Close window

    } catch (err) {
      setError(
        err.response?.data?.error || "Transaction failed. Please try again."
      );
    } finally {
      setLoading(false);
    }
  };

  // ================================
  // UI
  // ================================
  return (
    <div className="container" id="trade-window">

      <div className="regular-order">

        {/* 🔥 GRAPH FIRST */}
        {graphData && (
          <div style={{ width: "100%", marginBottom: "50px" }}>
            <VerticalGraph data={graphData} />
          </div>
        )}

        <h3 style={{ marginBottom: "25px" }}>
          {mode} {uid}
        </h3>

        {/* BUY / SELL TOGGLE */}
        <div style={{ display: "flex", gap: "20px", marginBottom: "25px" }}>
          <button
            className={`btn ${mode === "BUY" ? "btn-blue" : "btn-grey"}`}
            onClick={() => setMode("BUY")}
            disabled={loading}
          >
            Buy
          </button>

          <button
            className={`btn ${mode === "SELL" ? "btn-blue" : "btn-grey"}`}
            onClick={() => setMode("SELL")}
            disabled={loading}
          >
            Sell
          </button>
        </div>

        {/* INPUTS */}
        <div className="inputs">
          <fieldset>
            <legend>Quantity</legend>
            <input
              type="number"
              min="1"
              value={stockQuantity}
              onChange={(e) => setStockQuantity(Number(e.target.value))}
              disabled={loading}
            />
          </fieldset>

          <fieldset>
            <legend>Price</legend>
            <input
              type="number"
              step="0.05"
              min="0.05"
              value={stockPrice}
              onChange={(e) => setStockPrice(Number(e.target.value))}
              disabled={loading}
            />
          </fieldset>
        </div>

        {/* TOTAL */}
        <div style={{ marginTop: "20px", fontSize: "1.1rem", fontWeight: 600 }}>
          Total: ₹{totalAmount.toLocaleString("en-IN")}
        </div>

        {/* ERROR */}
        {error && (
          <div style={{ color: "#ff4d4f", marginTop: "15px" }}>
            {error}
          </div>
        )}

      </div>

      {/* ACTION BUTTONS */}
      <div className="buttons">
        <span>
          Required: ₹{totalAmount.toLocaleString("en-IN")}
        </span>

        <div style={{ display: "flex", gap: "25px" }}>
          <button
            className="btn btn-blue"
            onClick={handleSubmit}
            disabled={loading}
          >
            {loading ? "Processing..." : mode}
          </button>

          <button
            className="btn btn-grey"
            onClick={closeBuyWindow}
            disabled={loading}
          >
            Cancel
          </button>
        </div>
      </div>

    </div>
  );
};

export default BuyActionWindow;
